using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability via the DuckDuckGo Instant Answer API.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _http;

    public WebSearchTool(HttpClient httpClient)
    {
        _http = httpClient;
        _http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    }

    [Description("Search the web for information on a given query. Returns relevant summaries and links.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        var json = await _http.GetStringAsync(url, cancellationToken);
        var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var results = new List<string>();

        if (root.TryGetProperty("Heading", out var heading)
            && heading.GetString() is { Length: > 0 } headingText)
        {
            results.Add($"# {headingText}");
        }

        if (root.TryGetProperty("Abstract", out var abs)
            && abs.GetString() is { Length: > 0 } abstractText)
        {
            results.Add($"Summary: {abstractText}");

            if (root.TryGetProperty("AbstractSource", out var src))
                results.Add($"Source: {src.GetString()}");

            if (root.TryGetProperty("AbstractURL", out var absUrl))
                results.Add($"URL: {absUrl.GetString()}");
        }

        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            var topicEntries = new List<string>();
            foreach (var topic in topics.EnumerateArray().Take(8))
            {
                if (topic.TryGetProperty("Text", out var text)
                    && text.GetString() is { Length: > 0 } topicText)
                {
                    var topicUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                    topicEntries.Add($"- {topicText} ({topicUrl})");
                }

                // Handle sub-topics (grouped results)
                if (topic.TryGetProperty("Topics", out var subTopics))
                {
                    foreach (var sub in subTopics.EnumerateArray().Take(3))
                    {
                        if (sub.TryGetProperty("Text", out var subText)
                            && subText.GetString() is { Length: > 0 } subTopicText)
                        {
                            var subUrl = sub.TryGetProperty("FirstURL", out var su) ? su.GetString() : "";
                            topicEntries.Add($"- {subTopicText} ({subUrl})");
                        }
                    }
                }
            }

            if (topicEntries.Count > 0)
            {
                results.Add("\nRelated topics:");
                results.AddRange(topicEntries);
            }
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : "No results found. Try rephrasing the query or using different keywords.";
    }

    public AIFunction AsAIFunction() =>
        AIFunctionFactory.Create(SearchWebAsync, this);
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability for the research agent to record findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description("Save a research note with a category tag. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short category label (e.g. 'definition', 'history', 'key-fact', 'statistic')")] string category,
        [Description("The content of the note")] string content,
        [Description("The source URL or reference, if available")] string? source = null)
    {
        var note = new Note(category, content, source);
        _notes.Add(note);
        return $"Note #{_notes.Count} saved under '{category}'.";
    }

    [Description("Retrieve all saved research notes. Use this before writing a summary to review what you've collected.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var grouped = _notes
            .Select((n, i) => (Index: i + 1, Note: n))
            .GroupBy(x => x.Note.Category);

        var lines = new List<string> { $"=== {_notes.Count} note(s) saved ===\n" };

        foreach (var group in grouped)
        {
            lines.Add($"[{group.Key}]");
            foreach (var (index, note) in group)
            {
                lines.Add($"  #{index}: {note.Content}");
                if (note.Source is not null)
                    lines.Add($"        Source: {note.Source}");
            }
            lines.Add("");
        }

        return string.Join("\n", lines);
    }

    public IList<AIFunction> AsAIFunctions() =>
    [
        AIFunctionFactory.Create(SaveNote, this),
        AIFunctionFactory.Create(GetNotes, this),
    ];
}

public sealed record Note(string Category, string Content, string? Source);

