arguments.new_str:
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build tools -------------------------------------------------------------

using var httpClient = new HttpClient();
var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

var tools = new List<AITool> { webSearch.AsAIFunction() };
tools.AddRange(noteTaking.AsAIFunctions());

// --- Build the chat client + agent -------------------------------------------

var openAiClient = new OpenAIClient(apiKey);

IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user
    provides by following these steps:

    1. **Search** – Use the SearchWebAsync tool multiple times with varied queries
       to gather broad and specific information about the topic.
    2. **Take notes** – After each search, use SaveNote to record the most important
       findings. Tag each note with a category (e.g. 'definition', 'history',
       'key-fact', 'statistic', 'application').
    3. **Iterate** – Refine your queries based on what you've learned. Search at
       least 3 times with different angles before summarizing.
    4. **Review** – Call GetNotes to review all collected findings.
    5. **Summarize** – Write a well-structured summary of the topic, organized by
       category, citing sources where available.

    Be thorough but concise. Prioritize accuracy and breadth of coverage.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking tools",
    tools: tools);

// --- Run the agent -----------------------------------------------------------

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync("research-session");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (update.Role == ChatRole.Assistant)
    {
        Console.Write(update.Text);
    }
    else if (update.Role == ChatRole.Tool)
    {
        // Show tool activity as progress indicators
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.Write(".");
        Console.ResetColor();
    }
}

Console.WriteLine();

// --- Print collected notes ---------------------------------------------------

if (noteTaking.Notes.Count > 0)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.WriteLine($"\n📝 {noteTaking.Notes.Count} research note(s) collected during this session.");
    Console.ResetColor();
}

// --- Helpers -----------------------------------------------------------------

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(input)
        ? throw new InvalidOperationException("No topic provided.")
        : input;
}

