 using Microsoft.Extensions.AI;

 namespace ResearchAgent.Tools;

 /// <summary>
 /// Provides note-taking capability for the research agent to record findings.
 /// </summary>
 public sealed class NoteTakingTool
 {
     private readonly List<Note> _notes = [];

     public IReadOnlyList<Note> Notes => _notes;

     [Description("Save a research note with a category tag. Use this to record important findings during research.")]
     public string SaveNote(
         [Description("A short category label (e.g. 'definition', 'history', 'key-fact', 'statistic')")] string category,
         [Description("The content of the note")] string content,
         [Description("The source URL or reference, if available")] string? source = null)
     {
         var note = new Note(category, content, source);
         _notes.Add(note);
         return $"Note #{_notes.Count} saved under '{category}'.";
     }

     [Description("Retrieve all saved research notes. Use this before writing a summary to review what you've collected.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         var grouped = _notes
             .Select((n, i) => (Index: i + 1, Note: n))
             .GroupBy(x => x.Note.Category);

         var lines = new List<string> { $"=== {_notes.Count} note(s) saved ===\n" };

         foreach (var group in grouped)
         {
             lines.Add($"[{group.Key}]");
             foreach (var (index, note) in group)
             {
                 lines.Add($"  #{index}: {note.Content}");
                 if (note.Source is not null)
                     lines.Add($"        Source: {note.Source}");
             }
             lines.Add("");
         }

         return string.Join("\n", lines);
     }

     public IList<AIFunction> AsAIFunctions() =>
     [
         AIFunctionFactory.Create(SaveNote),
         AIFunctionFactory.Create(GetNotes),
     ];
 }

 public sealed record Note(string Category, string Content, string? Source);

